export const nextGeneration = (liveCells: Cell[]): Cell[] => {
  const countLiveNeighbors = (cell: Cell): number =>
    liveCells.filter((other) => isNeighbor(cell, other)).length;

  const isAlive = ([x, y]: Cell): boolean =>
    liveCells.some(([lx, ly]) => lx === x && ly === y);

  const survivors = liveCells.filter((cell) => countLiveNeighbors(cell) === 3);

  const born: Cell[] = [];
  const seen = new Set<string>();
  for (const [x, y] of liveCells) {
    for (let dx = -1; dx <= 1; dx++) {
      for (let dy = -1; dy <= 1; dy++) {
        const candidate: Cell = [x + dx, y + dy];
        const key = `${candidate[0]},${candidate[1]}`;
        if (seen.has(key)) continue;
        seen.add(key);
        if (!isAlive(candidate) && countLiveNeighbors(candidate) === 3) {
          born.push(candidate);
        }
      }
    }
  }

  return [...survivors, ...born];
};
